#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int n,m,t,h[N],l[N],s[N];

int main(){
    scanf("%d%d%d",&n,&m,&t);
    for(int i=0;i<t;i++){
        int x,y;
        scanf("%d%d",&x,&y);
        h[x]++,l[y]++;
    }
    if(t%n && t%m)
        printf("impossible");
    else if(t%m){
        printf("row ");
        for(int i=1;i<=n;i++)
            s[i]=s[i-1]+h[i]-t/n;
        sort(s+1,s+n+1);
        long long res=0;
        for(int i=1;i<=n;i++)
            res+=abs(s[i]-s[(n+1)/2]);
        printf("%lld",res);
    }else if(t%n){
        printf("column ");
        for(int i=1;i<=m;i++)
            s[i]=s[i-1]+l[i]-t/m;
        sort(s+1,s+m+1);
        long long res=0;
        for(int i=1;i<=m;i++)
            res+=abs(s[i]-s[(m+1)/2]);
        printf("%lld",res);
    }else{
        printf("both ");
        for(int i=1;i<=n;i++)
            s[i]=s[i-1]+h[i]-t/n;
        sort(s+1,s+n+1);
        long long res=0;
        for(int i=1;i<=n;i++)
            res+=abs(s[i]-s[(n+1)/2]);
        for(int i=1;i<=m;i++)
            s[i]=s[i-1]+l[i]-t/m;
        sort(s+1,s+m+1);
        for(int i=1;i<=m;i++)
            res+=abs(s[i]-s[(m+1)/2]);
        printf("%lld",res);
    }
    return 0;
}
